package com.google.gson;
import java.lang.annotation.Annotation;
import java.lang.reflect.Type;
import java.util.Arrays;
import java.util.Collection;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class FieldAttributesTest {

  @Mock
  private Field mockField;

  private FieldAttributes fieldAttributes;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    fieldAttributes = new FieldAttributes(mockField);
  }

  @Test
  void testGetDeclaringClass_returnsDeclaringClassFromField() {
    Class<?> expectedClass = String.class;
    when(mockField.getDeclaringClass()).thenReturn(expectedClass);

    Class<?> actualClass = fieldAttributes.getDeclaringClass();

    assertSame(expectedClass, actualClass);
    verify(mockField).getDeclaringClass();
  }
}
